using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;

    public int OriginalSentenceCount { get; set; }

    public int SummarySentenceCount { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummaryService
{
    string Summarize(string documentText, int maxSentences);
    int CountSentences(string documentText);
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarization service that scores sentences by word frequency
/// and returns the top-ranked ones in their original order.
/// </summary>
public partial class DocumentSummaryService : IDocumentSummaryService
{
    private static readonly char[] s_wordSeparators = [' ', '\t', '\n', '\r'];

    private static readonly HashSet<string> s_stopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "it", "its",
        "this", "that", "from", "as", "be", "been", "being", "have", "has",
        "had", "do", "does", "did", "will", "would", "could", "should",
        "may", "might", "shall", "can", "not", "no", "so", "if", "then",
        "than", "too", "very", "just", "about", "above", "after", "again",
        "all", "also", "am", "any", "because", "before", "between", "both",
        "each", "few", "he", "her", "here", "him", "his", "how", "i",
        "into", "me", "more", "most", "my", "nor", "now", "only", "other",
        "our", "out", "over", "own", "same", "she", "some", "such",
        "their", "them", "there", "these", "they", "through", "under",
        "up", "we", "what", "when", "where", "which", "while", "who",
        "whom", "why", "you", "your"
    };

    public string Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitSentences(documentText);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = ScoreSentences(sentences, wordFrequencies);

        // Pick the top-scored sentences but preserve original order.
        var topIndices = scored
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .Select(s => s.Index)
            .Order()
            .ToList();

        return string.Join(" ", topIndices.Select(i => sentences[i]));
    }

    public int CountSentences(string documentText) =>
        SplitSentences(documentText).Count;

    private static List<string> SplitSentences(string text)
    {
        // Split on sentence-ending punctuation followed by whitespace or end-of-string.
        var parts = SentenceRegex().Split(text.Trim());
        return parts
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in ExtractWords(sentence))
            {
                if (!s_stopWords.Contains(word))
                    freq[word] = freq.TryGetValue(word, out var count) ? count + 1 : 1;
            }
        }

        return freq;
    }

    private static List<(int Index, double Score)> ScoreSentences(
        List<string> sentences,
        Dictionary<string, int> wordFrequencies)
    {
        var scored = new List<(int Index, double Score)>(sentences.Count);

        for (int i = 0; i < sentences.Count; i++)
        {
            var words = ExtractWords(sentences[i]);
            if (words.Count == 0)
            {
                scored.Add((i, 0));
                continue;
            }

            double total = words
                .Where(w => !s_stopWords.Contains(w))
                .Sum(w => wordFrequencies.TryGetValue(w, out var f) ? f : 0);

            // Normalize by word count to avoid bias toward long sentences.
            scored.Add((i, total / words.Count));
        }

        return scored;
    }

    private static List<string> ExtractWords(string sentence) =>
        sentence
            .Split(s_wordSeparators, StringSplitOptions.RemoveEmptyEntries)
            .Select(w => WordCleanupRegex().Replace(w, ""))
            .Where(w => w.Length > 0)
            .ToList();

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"[^\w'-]", RegexOptions.Compiled)]
    private static partial Regex WordCleanupRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController : ControllerBase
{
    private readonly IDocumentSummaryService _summaryService;

    public SummaryController(IDocumentSummaryService summaryService)
    {
        _summaryService = summaryService;
    }

    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var originalCount = _summaryService.CountSentences(request.DocumentText);
        var summary = _summaryService.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = originalCount,
            SummarySentenceCount = _summaryService.CountSentences(summary)
        });
    }
}

